// Deepfake-Pro: kombiniert mehrere Erkennungs-Engines zu einem gewichteten Gesamtscore.
async function run(input) {
  const url = String((input && input.imageUrl) || '').trim();
  if (!/^https?:\/\//.test(url)) return { fehler: 'Bitte eine vollstaendige Bild-URL (http/https) angeben.' };
  const seUser = String((input && input.sightengineUser) || '').trim();
  const seSecret = String((input && input.sightengineSecret) || '').trim();
  const aiornotKey = String((input && input.aiornotKey) || '').trim();

  const ergebnisse = [];

  // Engine 1: Sightengine (deepfake + genai)
  if (seUser && seSecret) {
    try {
      const ep = 'https://api.sightengine.com/1.0/check.json?models=deepfake,genai'
        + '&api_user=' + encodeURIComponent(seUser) + '&api_secret=' + encodeURIComponent(seSecret)
        + '&url=' + encodeURIComponent(url);
      const res = await fetch(ep);
      const d = await res.json();
      if (res.ok && d && d.status === 'success') {
        const score = Math.max(
          (d.type && typeof d.type.deepfake === 'number') ? d.type.deepfake : 0,
          (d.type && typeof d.type.ai_generated === 'number') ? d.type.ai_generated : 0
        );
        ergebnisse.push({ anbieter: 'Sightengine', ok: true, score: score });
      } else {
        ergebnisse.push({ anbieter: 'Sightengine', ok: false, fehler: (d && d.error && d.error.message) || ('HTTP ' + res.status) });
      }
    } catch (e) { ergebnisse.push({ anbieter: 'Sightengine', ok: false, fehler: 'nicht erreichbar' }); }
  }

  // Engine 2: AI or Not (KI-Bild-Erkennung)
  if (aiornotKey) {
    try {
      const res = await fetch('https://api.aiornot.com/v1/reports/image', {
        method: 'POST',
        headers: { 'authorization': 'Bearer ' + aiornotKey, 'content-type': 'application/json' },
        body: JSON.stringify({ object: url })
      });
      const d = await res.json();
      const rep = d && d.report;
      let score = null;
      if (rep && rep.ai && typeof rep.ai.confidence === 'number') score = rep.ai.confidence;
      else if (rep && rep.verdict) score = rep.verdict === 'ai' ? 0.8 : 0.2;
      if (res.ok && score != null) ergebnisse.push({ anbieter: 'AI or Not', ok: true, score: score });
      else ergebnisse.push({ anbieter: 'AI or Not', ok: false, fehler: (d && (d.error || d.message)) || ('HTTP ' + res.status) });
    } catch (e) { ergebnisse.push({ anbieter: 'AI or Not', ok: false, fehler: 'nicht erreichbar' }); }
  }

  const valide = ergebnisse.filter(function (r) { return r.ok; });
  if (!valide.length) return {
    fehler: 'Kein Erkennungsdienst lieferte ein Ergebnis. Mindestens einen Schluessel angeben — Sightengine (sightengineUser + sightengineSecret) und/oder AI or Not (aiornotKey).',
    versucht: ergebnisse
  };

  const scores = valide.map(function (r) { return r.score; });
  const avg = scores.reduce(function (a, b) { return a + b; }, 0) / scores.length;
  const max = Math.max.apply(null, scores);
  const gesamt = (avg + max) / 2; // hoechstes Signal staerker gewichtet

  function stufe(s) {
    if (s < 0.2) return 'sehr wahrscheinlich echt';
    if (s < 0.5) return 'unklar';
    if (s < 0.8) return 'wahrscheinlich manipuliert';
    return 'sehr wahrscheinlich manipuliert';
  }

  return {
    gesamtscore: Math.round(gesamt * 1000) / 1000,
    prozent: Math.round(gesamt * 100) + '%',
    bewertung: stufe(gesamt),
    anbieterAusgewertet: valide.length,
    einzelergebnisse: ergebnisse.map(function (r) {
      return r.ok ? { anbieter: r.anbieter, score: Math.round(r.score * 100) + '%' } : { anbieter: r.anbieter, fehler: r.fehler };
    }),
    begruendung: valide.length + ' Engine(s) kombiniert (Durchschnitt + hoechstes Einzelsignal gewichtet). Mehr Anbieter erhoehen die Zuverlaessigkeit.',
    hinweis: 'Wahrscheinlichkeit, kein forensischer Beweis.',
    bild: url
  };
}
